import React from 'react';
import { Link } from 'react-router-dom';

function Services() {
  const serviceData = [
    { id: 1, title: "Web Development", icon: "fas fa-code", color: "#0d6efd", img: "https://images.unsplash.com", desc: "Building high-speed, futuristic websites that convert visitors into customers." },
    { id: 2, title: "UI/UX Design", icon: "fas fa-layer-group", color: "#dc3545", img: "https://images.unsplash.com", desc: "Pixel-perfect designs focused on user psychology and modern aesthetics." },
    { id: 3, title: "App Development", icon: "fas fa-mobile-alt", color: "#198754", img: "https://images.unsplash.com", desc: "Powerful native and cross-platform apps with seamless user experiences." },
    { id: 4, title: "Assignment Support", icon: "fas fa-book-reader", color: "#ffc107", img: "https://images.unsplash.com", desc: "Expert academic guidance to help you excel in your technical projects." },
    { id: 5, title: "PPT Design", icon: "fas fa-file-powerpoint", color: "#0dcaf0", img: "https://images.unsplash.com", desc: "High-impact visual storytelling that makes your presentations memorable." },
    { id: 6, title: "Report Writing", icon: "fas fa-file-signature", color: "#6c757d", img: "https://images.unsplash.com", desc: "Professional, data-driven technical reports and business documentation." },
    { id: 7, title: "Digital Marketing", icon: "fas fa-bullhorn", color: "#343a40", img: "https://images.unsplash.com", desc: "Strategic campaigns to enhance your online presence and market reach." },
    { id: 8, title: "Content Writing", icon: "fas fa-pen-nib", color: "#0d6efd", img: "https://images.unsplash.com", desc: "Engaging and SEO-optimized content that speaks your brand's voice." },
    { id: 9, title: "SEO Optimization", icon: "fas fa-search-plus", color: "#20c997", img: "https://images.unsplash.com", desc: "Improve your search engine rankings and attract organic traffic." }
  ];

  return (
    <div className="services-page py-5" style={{ backgroundColor: '#f8f9fa' }}>
      <div className="container py-4">
        {/* Modern Header */}
        <div className="text-center mb-5">
          <h2 className="fw-bold display-5 mb-2">My Premium <span style={{ color: '#0d6efd' }}>Services</span></h2>
          <p className="text-muted fs-5">Innovative solutions for your digital and academic success in 2026.</p>
          <div className="mx-auto" style={{ width: '50px', height: '4px', background: '#0d6efd', borderRadius: '10px' }}></div>
        </div>

        {/* 9 Professional Cards */}
        <div className="row g-4">
          {serviceData.map((service) => (
            <div className="col-lg-4 col-md-6" key={service.id}>
              <div className="card h-100 border-0 shadow-sm service-card-pro">
                
                {/* Image Section */}
                <div className="img-container">
                  <img src={service.img} alt={service.title} className="card-img-top pro-img" />
                  <div className="icon-overlay shadow" style={{ backgroundColor: service.color }}>
                    <i className={service.icon}></i>
                  </div>
                </div>

                {/* Content Section */}
                <div className="card-body p-4 text-center">
                  <h4 className="fw-bold mb-3">{service.title}</h4>
                  <p className="text-muted small mb-4">{service.desc}</p>
                  <Link to="/register" className="btn btn-dark w-100 rounded-pill fw-bold py-2 shadow-sm">
                    Get Started
                  </Link>
                </div>

              </div>
            </div>
          ))}
        </div>
      </div>

      <style>{`
        .service-card-pro {
          border-radius: 20px;
          overflow: hidden;
          transition: all 0.4s ease;
          background: #ffffff;
        }

        .img-container {
          position: relative;
          height: 180px;
          overflow: hidden;
        }

        .pro-img {
          width: 100%;
          height: 100%;
          object-fit: cover;
          transition: transform 0.6s ease;
        }

        .icon-overlay {
          position: absolute;
          bottom: -20px;
          left: 50%;
          transform: translateX(-50%);
          width: 50px;
          height: 50px;
          border-radius: 12px;
          display: flex;
          align-items: center;
          justify-content: center;
          color: white;
          font-size: 1.2rem;
          border: 3px solid white;
          z-index: 2;
        }

        .service-card-pro:hover {
          transform: translateY(-10px);
          box-shadow: 0 15px 35px rgba(0,0,0,0.1) !important;
        }

        .service-card-pro:hover .pro-img {
          transform: scale(1.1);
        }

        .btn-dark:hover {
          background-color: #0d6efd !important;
          border-color: #0d6efd !important;
        }
      `}</style>
    </div>
  );
}

export default Services;
